                React.createElement('div', { className: 'advice-expert-evidence__label' }, '–Ъ–∞–Ї–Њ–є –Љ–µ—Е–∞–љ–Є–Ј–Љ –Ј–і–µ—Б—М –≤–∞–ґ–µ–љ'),
                React.createElement('div', { className: 'advice-expert-evidence__text' }, expertMeta.causal.mechanism)
